import java.util.*;

public class KruskalMST {

    int[] parent, rank;

    int find(int x) {
        if (parent[x] != x) parent[x] = find(parent[x]); // path compression
        return parent[x];
    }

    boolean union(int a, int b) {
        int ra = find(a), rb = find(b);
        if (ra == rb) return false; // same component => cycle
        if (rank[ra] < rank[rb]) parent[ra] = rb;
        else if (rank[ra] > rank[rb]) parent[rb] = ra;
        else { parent[rb] = ra; rank[ra]++; }
        return true;
    }

    public List<int[]> kruskal(int V, int[][] edges) {
        // edges[i] = {u, v, weight}
        parent = new int[V]; rank = new int[V];
        for (int i = 0; i < V; i++) parent[i] = i;

        // TODO: Sort edges by weight, then iterate and add edge if union returns true
        List<int[]> mst = new ArrayList<>();

        return mst;
    }

    public static void main(String[] args) {
        KruskalMST k = new KruskalMST();
        int[][] edges = {
            {0,1,10},{0,2,6},{0,3,5},{1,3,15},{2,3,4}
        };
        List<int[]> mst = k.kruskal(4, edges);
        int total = 0;
        for (int[] e : mst) {
            System.out.println(e[0] + " - " + e[1] + " : " + e[2]);
            total += e[2];
        }
        System.out.println("Total weight: " + total);
    }
}

import java.util.*;

public class PrimMST {

    public int primMSTWeight(int V, List<int[]>[] adj) {
        boolean[] inMST = new boolean[V];
        int[] key = new int[V]; // min edge weight to include vertex in MST
        Arrays.fill(key, Integer.MAX_VALUE);
        key[0] = 0;

        // PriorityQueue of {weight, vertex}
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a -> a[0]));
        pq.offer(new int[]{0, 0});
        int totalWeight = 0;

        while (!pq.isEmpty()) {
            int[] curr = pq.poll();
            int w = curr[0], u = curr[1];
            if (inMST[u]) continue;
            inMST[u] = true;
            totalWeight += w;
            // TODO: for each neighbor {v, weight} of u:
            //       if !inMST[v] && weight < key[v], update key[v] and add to pq
        }
        return totalWeight;
    }

    @SuppressWarnings("unchecked")
    public static void main(String[] args) {
        int V = 4;
        List<int[]>[] adj = new ArrayList[V];
        for (int i = 0; i < V; i++) adj[i] = new ArrayList<>();
        int[][] edges = {{0,1,10},{0,2,6},{0,3,5},{1,3,15},{2,3,4}};
        for (int[] e : edges) {
            adj[e[0]].add(new int[]{e[1], e[2]});
            adj[e[1]].add(new int[]{e[0], e[2]}); // undirected
        }
        PrimMST p = new PrimMST();
        System.out.println("MST weight: " + p.primMSTWeight(V, adj));
    }
}

import java.util.*;

public class MSTAnalysis {

    // --- Union-Find helpers ---
    int[] parent, rnk;
    void initUF(int n){ parent=new int[n]; rnk=new int[n]; for(int i=0;i<n;i++) parent[i]=i; }
    int find(int x){ return parent[x]==x?x:(parent[x]=find(parent[x])); }
    boolean union(int a,int b){ int ra=find(a),rb=find(b); if(ra==rb)return false;
        if(rnk[ra]<rnk[rb])parent[ra]=rb; else if(rnk[ra]>rnk[rb])parent[rb]=ra;
        else{parent[rb]=ra;rnk[ra]++;} return true; }

    public int kruskalWeight(int V, int[][] edges) {
        initUF(V);
        Arrays.sort(edges, Comparator.comparingInt(e -> e[2]));
        int total = 0, count = 0;
        for (int[] e : edges) {
            if (union(e[0], e[1])) { total += e[2]; count++; }
            if (count == V - 1) break;
        }
        return total;
    }

    @SuppressWarnings("unchecked")
    public int primWeight(int V, int[][] edges) {
        List<int[]>[] adj = new ArrayList[V];
        for (int i = 0; i < V; i++) adj[i] = new ArrayList<>();
        for (int[] e : edges) { adj[e[0]].add(new int[]{e[1],e[2]}); adj[e[1]].add(new int[]{e[0],e[2]}); }
        boolean[] vis = new boolean[V];
        int[] key = new int[V]; Arrays.fill(key, Integer.MAX_VALUE); key[0] = 0;
        PriorityQueue<int[]> pq = new PriorityQueue<>(Comparator.comparingInt(a->a[0]));
        pq.offer(new int[]{0,0});
        int total = 0;
        while (!pq.isEmpty()) {
            int[] cur = pq.poll(); int w=cur[0],u=cur[1];
            if (vis[u]) continue; vis[u]=true; total+=w;
            for (int[] nb:adj[u]) if(!vis[nb[0]]&&nb[1]<key[nb[0]]){key[nb[0]]=nb[1];pq.offer(new int[]{nb[1],nb[0]});}
        }
        return total;
    }

    public static void main(String[] args) {
        MSTAnalysis m = new MSTAnalysis();
        int[][] edges = {{0,1,10},{0,2,6},{0,3,5},{1,3,15},{2,3,4}};
        int kw = m.kruskalWeight(4, edges);
        int pw = m.primWeight(4, edges);
        System.out.println("Kruskal MST weight: " + kw);
        System.out.println("Prim MST weight: "    + pw);
        System.out.println("Same result: " + (kw == pw));
        System.out.println("MST edge count: " + (4 - 1)); // V-1
    }
}
